  ('police-8a5d488d-moex-00143', 'police-8a5d488d', 'police-8a5d488d-moex-112-15a7b19c', 'sub-police-8a5d488d-01', NULL, 'single_choice', '依憲法增修條文及司法院大法官解釋，下列有關全民健康保險（下稱全民健保）之敘述，何 者錯誤？', '["憲法增修條文明定國家有實施全民健保的義務", "全民健保是社會保險，但國家亦應尊重國民之個人意願，不得強制國民納保", "全民健保依被保險人的收入，收取不同保險費，符合量能負擔原則", "因全民健保所生對人民權利義務之影響，應有明確規範，並受法律保留原則之拘束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:02+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "507", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "交通警察人員交通組"}'::jsonb, NULL),
  ('police-8a5d488d-moex-00144', 'police-8a5d488d', 'police-8a5d488d-moex-112-15a7b19c', 'sub-police-8a5d488d-01', NULL, 'single_choice', '依司法院大法官解釋意旨，下列何者非屬大學自治之保障內容？', '["關於大學教師薪俸之事項", "直接關涉教學之學術事項", "大學之內部組織自主權", "以成績未達一定標準為由，將學生予以退學"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:02+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "507", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "交通警察人員交通組"}'::jsonb, NULL),
  ('police-8a5d488d-moex-00145', 'police-8a5d488d', 'police-8a5d488d-moex-112-15a7b19c', 'sub-police-8a5d488d-01', NULL, 'single_choice', '依司法院解釋意旨，有關平等權或平等原則之司法審查，下列敘述何者錯誤？', '["法院於適用平等原則時，必須審查差別待遇之目的是否合憲", "憲法第7條以「男女、宗教、種族、階級、黨派」作為差別待遇依據，一律適用嚴格審查 基準", "憲法第7條所定之平等權，係為保障人民在法律上地位之實質平等", "司法院大法官解釋常認平等係指「等者等之，不等者不等之」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:02+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "507", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "交通警察人員交通組"}'::jsonb, NULL),
  ('police-8a5d488d-moex-00146', 'police-8a5d488d', 'police-8a5d488d-moex-112-15a7b19c', 'sub-police-8a5d488d-01', NULL, 'single_choice', '依憲法增修條文第2條之規定，副總統缺位時，總統應如何處理？', '["於3個月內提名候選人，由立法院補選", "於1個月內提名候選人，由行政院院會同意", "於3個月內提名候選人，交由公民補選", "讓副總統維持缺位，不必作任何處理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:02+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "507", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "交通警察人員交通組"}'::jsonb, NULL),
  ('police-8a5d488d-moex-00147', 'police-8a5d488d', 'police-8a5d488d-moex-112-15a7b19c', 'sub-police-8a5d488d-01', NULL, 'single_choice', '依憲法及增修條文之規定，下列敘述何者錯誤？', '["總統對於院與院間之爭執，除憲法有規定者外，得召集有關各院院長會商解決", "總統解散立法院之命令，無須行政院院長之副署，不適用憲法第37條", "總統得經行政院會議之決議，發布緊急命令，不受憲法第43條之限制", "行政院院長不信任案後通過後，總統得不經諮詢立法院院長，直接宣告解散立法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:02+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "507", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "交通警察人員交通組"}'::jsonb, NULL),
  ('police-8a5d488d-moex-00148', 'police-8a5d488d', 'police-8a5d488d-moex-112-15a7b19c', 'sub-police-8a5d488d-01', NULL, 'single_choice', '下列有關獨立行政機關之敘述，何者錯誤？', '["所謂獨立行政機關，係指依據法律獨立行使職權之合議制機關", "獨立行政機關不適用行政一體原則，故不受行政院院長之指揮與監督", "立法院對獨立行政機關人事之決定，仍得施以一定限制，以為制衡", "行政院所屬之中央選舉委員會、公平交易委員會、國家通訊傳播委員會均屬獨立行政機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:02+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "507", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "交通警察人員交通組"}'::jsonb, NULL),
  ('police-8a5d488d-moex-00149', 'police-8a5d488d', 'police-8a5d488d-moex-112-15a7b19c', 'sub-police-8a5d488d-01', NULL, 'single_choice', '依憲法及增修條文規定，關於立法委員，下列敘述何者錯誤？', '["立法委員不得兼任官吏", "立法委員在院內所為之言論，對院外不負責任", "立法委員在院內所為之表決，對院外不負責任", "立法委員，除現行犯及叛亂罪外，在會期中非經立法院許可，不得逮捕或拘禁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:02+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "507", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "交通警察人員交通組"}'::jsonb, NULL),
