  ('police-8a5d488d-moex-00152', 'police-8a5d488d', 'police-8a5d488d-moex-112-15a7b19c', 'sub-police-8a5d488d-01', NULL, 'single_choice', '關於臺北市政府發布之建築物施工鄰損事件爭議處理規則，下列敘述何者錯誤？', '["此為地方自治團體之自治規則", "若無自治條例授權，不得直接規範人民權利義務", "如其有牴觸授權之自治條例，由中央各該主管機關函告無效", "因其為依自治條例授權所訂定者，應函報上級主管機關核定後實施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:02+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "507", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "交通警察人員交通組"}'::jsonb, NULL)
